import bisect

class ProductInventory:
    def __init__(self):
        self.products = []
        self.sku_set = set()

    def add_product(self, sku, product_data):
        if not self._validate_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku in self.sku_set:
            raise ValueError("Duplicate SKU")

        bisect.insort(self.products, (sku, product_data))
        self.sku_set.add(sku)

    def update_product(self, sku, new_product_data):
        if not self._validate_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku not in self.sku_set:
            raise KeyError("SKU not found")

        index = self._find_index(sku)
        self.products[index] = (sku, new_product_data)

    def delete_product(self, sku):
        if not self._validate_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku not in self.sku_set:
            raise KeyError("SKU not found")

        index = self._find_index(sku)
        del self.products[index]
        self.sku_set.remove(sku)

    def search_product(self, sku):
        if not self._validate_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku not in self.sku_set:
            return None

        index = self._find_index(sku)
        return self.products[index][1]

    def _find_index(self, sku):
        i = bisect.bisect_left(self.products, (sku,))
        if i != len(self.products) and self.products[i][0] == sku:
            return i
        raise KeyError("SKU not found")

    def _validate_sku(self, sku):
        return isinstance(sku, str) and sku.isalnum()
