#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SEATS 100

typedef struct {
    int front, rear;
    int seats[MAX_SEATS];
} Queue;

void initializeQueue(Queue *q) {
    q->front = -1;
    q->rear = -1;
}

bool isEmpty(Queue *q) {
    return q->front == -1;
}

bool isFull(Queue *q) {
    return (q->rear + 1) % MAX_SEATS == q->front;
}

void enqueue(Queue *q, int seat) {
    if (isFull(q)) {
        printf("Queue is full. Cannot enqueue.\n");
        return;
    }
    if (isEmpty(q)) {
        q->front = 0;
    }
    q->rear = (q->rear + 1) % MAX_SEATS;
    q->seats[q->rear] = seat;
}

int dequeue(Queue *q) {
    if (isEmpty(q)) {
        printf("Queue is empty. Cannot dequeue.\n");
        return -1;
    }
    int seat = q->seats[q->front];
    if (q->front == q->rear) {
        q->front = q->rear = -1;
    } else {
        q->front = (q->front + 1) % MAX_SEATS;
    }
    return seat;
}

void bookSeat(Queue *q, int *availableSeats) {
    if (*availableSeats <= 0) {
        printf("No seats available. Overbooking attempt!\n");
        return;
    }
    int seat = dequeue(q);
    if (seat != -1) {
        printf("Seat %d booked successfully.\n", seat);
        (*availableSeats)--;
    }
}

void cancelSeat(Queue *q, int seat, int *availableSeats) {
    if (isFull(q)) {
        printf("Cannot cancel seat. Queue is full.\n");
        return;
    }
    enqueue(q, seat);
    printf("Seat %d cancelled successfully.\n", seat);
    (*availableSeats)++;
}

int main() {
    Queue seatQueue;
    initializeQueue(&seatQueue);
    int availableSeats = MAX_SEATS;

    // Initialize all seats
    for (int i = 1; i <= MAX_SEATS; i++) {
        enqueue(&seatQueue, i);
    }

    // Example usage
    bookSeat(&seatQueue, &availableSeats);
    bookSeat(&seatQueue, &availableSeats);
    cancelSeat(&seatQueue, 1, &availableSeats);
    bookSeat(&seatQueue, &availableSeats);

    return 0;
}
