#include <iostream>
#include <vector>
#include <algorithm>
#include <utility>

struct LogEntry {
    long timestamp;
    std::string event;
};

class LogManager {
private:
    std::vector<LogEntry> logs;

    // Helper function for binary search to find the first occurrence >= timestamp
    int lowerBound(long timestamp) {
        int left = 0;
        int right = logs.size();
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (logs[mid].timestamp < timestamp) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

    // Helper function for binary search to find the last occurrence <= timestamp
    int upperBound(long timestamp) {
        int left = 0;
        int right = logs.size();
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (logs[mid].timestamp <= timestamp) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

public:
    void addLog(long timestamp, const std::string& event) {
        LogEntry entry{timestamp, event};
        auto it = std::upper_bound(logs.begin(), logs.end(), entry, 
            [](const LogEntry& a, const LogEntry& b) { return a.timestamp < b.timestamp; });
        logs.insert(it, entry);
    }

    std::vector<LogEntry> queryRange(long start, long end) {
        std::vector<LogEntry> result;
        int lower = lowerBound(start);
        int upper = upperBound(end);
        for (int i = lower; i < upper; ++i) {
            result.push_back(logs[i]);
        }
        return result;
    }
};

int main() {
    LogManager manager;
    // Example usage:
    manager.addLog(1617181723, "User login");
    manager.addLog(1617181725, "User logout");
    manager.addLog(1617181725, "System error");
    manager.addLog(1617181730, "Data update");

    auto results = manager.queryRange(1617181725, 1617181725);
    for (const auto& entry : results) {
        std::cout << entry.timestamp << ": " << entry.event << std::endl;
    }

    return 0;
}
