import java.util.*;

class LCA {
    private int LOG;
    private int[] depth;
    private int[][] up;

    public LCA(List<List<Integer>> tree, int root) {
        int n = tree.size();
        LOG = 1;
        while ((1 << LOG) <= n) LOG++;
        depth = new int[n];
        up = new int[n][LOG];

        for (int i = 0; i < n; i++) {
            Arrays.fill(up[i], -1);
        }

        dfs(tree, root, -1);
    }

    private void dfs(List<List<Integer>> tree, int node, int parent) {
        up[node][0] = parent;
        for (int i = 1; i < LOG; i++) {
            if (up[node][i - 1] != -1) {
                up[node][i] = up[up[node][i - 1]][i - 1];
            }
        }

        for (int child : tree.get(node)) {
            if (child != parent) {
                depth[child] = depth[node] + 1;
                dfs(tree, child, node);
            }
        }
    }

    public int findLCA(int u, int v) {
        if (depth[u] < depth[v]) {
            int temp = u;
            u = v;
            v = temp;
        }

        for (int i = LOG - 1; i >= 0; i--) {
            if (depth[u] - (1 << i) >= depth[v]) {
                u = up[u][i];
            }
        }

        if (u == v) return u;

        for (int i = LOG - 1; i >= 0; i--) {
            if (up[u][i] != -1 && up[u][i] != up[v][i]) {
                u = up[u][i];
                v = up[v][i];
            }
        }

        return up[u][0];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        List<List<Integer>> tree = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            tree.add(new ArrayList<>());
        }

        for (int i = 0; i < n - 1; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            tree.get(u).add(v);
            tree.get(v).add(u);
        }

        int root = scanner.nextInt();
        LCA lca = new LCA(tree, root);

        int q = scanner.nextInt();
        while (q-- > 0) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            System.out.println(lca.findLCA(u, v));
        }
    }
}
