#include <mutex>
#include <thread>
#include <memory>

namespace fs = std::filesystem;

class DocumentParser {
public:
    virtual std::string parse(const std::string& content) = 0;
    virtual ~DocumentParser() = default;
};

class TextParser : public DocumentParser {
public:
    std::string parse(const std::string& content) override {
        return content;
    }
};

class InvertedIndex {
private:
    std::unordered_map<std::string, std::set<std::string>> index;
    std::mutex mtx;

    std::string normalizeToken(const std::string& token) {
        std::string normalized;
        for (char c : token) {
            if (std::isalpha(c)) {
                normalized += std::tolower(c);
            }
        }
        return normalized;
    }

public:
    void addDocument(const std::string& docId, const std::string& content) {
        std::istringstream iss(content);
        std::string token;
        while (iss >> token) {
            token = normalizeToken(token);
            if (!token.empty()) {
                std::lock_guard<std::mutex> lock(mtx);
                index[token].insert(docId);
            }
        }
    }

    std::set<std::string> search(const std::string& keyword) {
        std::string normalized = normalizeToken(keyword);
        std::lock_guard<std::mutex> lock(mtx);
        if (index.find(normalized) != index.end()) {
            return index[normalized];
        }
        return {};
    }
};

class DocumentLoader {
private:
    std::unordered_map<std::string, std::unique_ptr<DocumentParser>> parsers;
    InvertedIndex& index;

public:
    DocumentLoader(InvertedIndex& idx) : index(idx) {
        parsers[".txt"] = std::make_unique<TextParser>();
        // Add other parsers for different formats here
    }

    void loadDocument(const fs::path& filePath) {
        try {
            std::string ext = filePath.extension().string();
            if (parsers.find(ext) == parsers.end()) {
                std::cerr << "Unsupported format: " << ext << std::endl;
                return;
            }

            std::ifstream file(filePath);
            if (!file.is_open()) {
                std::cerr << "Failed to open: " << filePath << std::endl;
                return;
            }

            std::string content((std::istreambuf_iterator<char>(file)), 
                               std::istreambuf_iterator<char>());
            std::string docId = filePath.filename().string();
            index.addDocument(docId, parsers[ext]->parse(content));
        } catch (const std::exception& e) {
            std::cerr << "Error loading " << filePath << ": " << e.what() << std::endl;
        }
    }

    void loadDirectory(const fs::path& dirPath) {
        try {
            for (const auto& entry : fs::directory_iterator(dirPath)) {
                if (entry.is_regular_file()) {
                    loadDocument(entry.path());
                }
            }
        } catch (const std::exception& e) {
            std::cerr << "Error loading directory " << dirPath << ": " << e.what() << std::endl;
        }
    }
};

int main() {
    InvertedIndex index;
    DocumentLoader loader(index);

    std::string inputPath;
    std::cout << "Enter document or directory path: ";
    std::cin >> inputPath;

    if (fs::is_directory(inputPath)) {
        loader.loadDirectory(inputPath);
    } else if (fs::is_regular_file(inputPath)) {
        loader.loadDocument(inputPath);
    } else {
        std::cerr << "Invalid path: " << inputPath << std::endl;
        return 1;
    }

    std::string query;
    while (true) {
        std::cout << "Enter search term (or 'exit' to quit): ";
        std::cin >> query;
        if (query == "exit") break;

        auto results = index.search(query);
        if (results.empty()) {
            std::cout << "No results found." << std::endl;
        } else {
            std::cout << "Found in documents: ";
            for (const auto& doc : results) {
                std::cout << doc << " ";
            }
            std::cout << std::endl;
        }
    }

    return 0;
}
