use std::fs::File;
use std::io::{self, BufRead};
use std::path::Path;
use num_bigint::BigUint;
use num_traits::{Zero, One};
use rand::Rng;

fn read_numbers_from_file<P>(filename: P) -> io::Result<Vec<String>>
where
    P: AsRef<Path>,
{
    let file = File::open(filename)?;
    let lines = io::BufReader::new(file).lines();
    let mut numbers = Vec::new();

    for line in lines {
        let line = line?;
        let trimmed = line.trim();
        if !trimmed.is_empty() {
            numbers.push(trimmed.to_string());
        }
    }

    Ok(numbers)
}

fn is_prime(n: &BigUint, k: usize) -> bool {
    if n <= &BigUint::one() {
        return false;
    }
    if n <= &BigUint::from(3u32) {
        return true;
    }

    let mut d = n - BigUint::one();
    let mut s = 0;

    while &d % BigUint::from(2u32) == BigUint::zero() {
        d /= BigUint::from(2u32);
        s += 1;
    }

    let mut rng = rand::thread_rng();

    for _ in 0..k {
        let a = rng.gen_biguint_range(&BigUint::from(2u32), &(n - BigUint::one()));
        let mut x = a.modpow(&d, n);

        if x == BigUint::one() || x == n - BigUint::one() {
            continue;
        }

        let mut is_composite = true;
        for _ in 0..s - 1 {
            x = x.modpow(&BigUint::from(2u32), n);
            if x == n - BigUint::one() {
                is_composite = false;
                break;
            }
        }

        if is_composite {
            return false;
        }
    }

    true
}

fn main() {
    let filename = "numbers.txt";
    let numbers = match read_numbers_from_file(filename) {
        Ok(nums) => nums,
        Err(e) => {
            eprintln!("Error reading file: {}", e);
            return;
        }
    };

    for num_str in numbers {
        let num = match num_str.parse::<BigUint>() {
            Ok(n) => n,
            Err(_) => {
                println!("Invalid number format: {}", num_str);
                continue;
            }
        };

        let is_prime = is_prime(&num, 5); // 5 iterations for good accuracy
        println!("{} is prime: {}", num, is_prime);
    }
}
