import java.io.*;
import java.util.Hashtable;

public class InventorySystem {
    private Hashtable<String, Item> inventory;
    private static final String FILE_NAME = "inventory_state.ser";

    public InventorySystem() {
        inventory = new Hashtable<>();
        loadInventory();
    }

    public void addItem(String id, String name, int quantity) {
        inventory.put(id, new Item(id, name, quantity));
        saveInventory();
    }

    public void removeItem(String id) {
        inventory.remove(id);
        saveInventory();
    }

    public Item findItem(String id) {
        return inventory.get(id);
    }

    private void saveInventory() {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(FILE_NAME))) {
            oos.writeObject(inventory);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    @SuppressWarnings("unchecked")
    private void loadInventory() {
        File file = new File(FILE_NAME);
        if (file.exists()) {
            try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(FILE_NAME))) {
                inventory = (Hashtable<String, Item>) ois.readObject();
            } catch (IOException | ClassNotFoundException e) {
                e.printStackTrace();
            }
        }
    }

    public static class Item implements Serializable {
        private String id;
        private String name;
        private int quantity;

        public Item(String id, String name, int quantity) {
            this.id = id;
            this.name = name;
            this.quantity = quantity;
        }

        public String getId() {
            return id;
        }

        public String getName() {
            return name;
        }

        public int getQuantity() {
            return quantity;
        }

        public void setQuantity(int quantity) {
            this.quantity = quantity;
        }
    }

    public static void main(String[] args) {
        InventorySystem system = new InventorySystem();
        system.addItem("001", "Laptop", 10);
        system.addItem("002", "Mouse", 50);
        Item item = system.findItem("001");
        if (item != null) {
            System.out.println("Found: " + item.getName() + " - " + item.getQuantity());
        }
        system.removeItem("002");
    }
}
