#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <stdexcept>

using namespace std;

class SuffixTree {
private:
    struct Node {
        unordered_map<char, Node*> children;
        int start;
        int* end;
        Node* suffixLink;
        int suffixIndex;

        Node(int start, int* end, Node* link) : start(start), end(end), suffixLink(link), suffixIndex(-1) {}
    };

    Node* root;
    Node* lastNewNode;
    Node* activeNode;
    int activeEdge;
    int activeLength;
    int remainingSuffixCount;
    int leafEnd;
    int* rootEnd;
    int* splitEnd;
    int size;
    string text;

    Node* newNode(int start, int* end) {
        Node* node = new Node(start, end, root);
        return node;
    }

    int edgeLength(Node* node) {
        return *(node->end) - node->start + 1;
    }

    bool walkDown(Node* node) {
        if (activeLength >= edgeLength(node)) {
            activeEdge += edgeLength(node);
            activeLength -= edgeLength(node);
            activeNode = node;
            return true;
        }
        return false;
    }

    void extendSuffixTree(int pos) {
        leafEnd = pos;
        remainingSuffixCount++;
        lastNewNode = nullptr;

        while (remainingSuffixCount > 0) {
            if (activeLength == 0) {
                activeEdge = pos;
            }

            if (activeNode->children.find(text[activeEdge]) == activeNode->children.end()) {
                activeNode->children[text[activeEdge]] = newNode(pos, &leafEnd);

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixLink = activeNode;
                    lastNewNode = nullptr;
                }
            } else {
                Node* next = activeNode->children[text[activeEdge]];
                if (walkDown(next)) {
                    continue;
                }

                if (text[next->start + activeLength] == text[pos]) {
                    if (lastNewNode != nullptr && activeNode != root) {
                        lastNewNode->suffixLink = activeNode;
                        lastNewNode = nullptr;
                    }
                    activeLength++;
                    break;
                }

                splitEnd = new int;
                *splitEnd = next->start + activeLength - 1;
                Node* split = newNode(next->start, splitEnd);
                activeNode->children[text[activeEdge]] = split;
                split->children[text[pos]] = newNode(pos, &leafEnd);
                next->start += activeLength;
                split->children[text[next->start]] = next;

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixLink = split;
                }

                lastNewNode = split;
            }

            remainingSuffixCount--;

            if (activeNode == root && activeLength > 0) {
                activeLength--;
                activeEdge = pos - remainingSuffixCount + 1;
            } else if (activeNode != root) {
                activeNode = activeNode->suffixLink;
            }
        }
    }

    void setSuffixIndex(Node* node, int labelHeight) {
        if (node == nullptr) return;

        bool isLeaf = true;
        for (auto it : node->children) {
            isLeaf = false;
            setSuffixIndex(it.second, labelHeight + edgeLength(it.second));
        }

        if (isLeaf) {
            node->suffixIndex = size - labelHeight;
        }
    }

    void buildSuffixTree() {
        size = text.size();
        rootEnd = new int;
        *rootEnd = -1;
        root = newNode(-1, rootEnd);
        activeNode = root;
        activeEdge = -1;
        activeLength = 0;
        remainingSuffixCount = 0;
        leafEnd = -1;

        for (int i = 0; i < size; i++) {
            extendSuffixTree(i);
        }

        setSuffixIndex(root, 0);
    }

    void collectSuffixIndices(Node* node, vector<int>& indices) {
        if (node == nullptr) return;

        if (node->suffixIndex != -1) {
            indices.push_back(node->suffixIndex);
            return;
        }

        for (auto it : node->children) {
            collectSuffixIndices(it.second, indices);
        }
    }

    void traverseAndSearch(Node* node, const string& pattern, int index, vector<int>& indices) {
        if (node == nullptr) return;

        if (node->suffixIndex == -1) {
            for (int i = node->start; i <= *(node->end) && index < pattern.size(); i++) {
                if (text[i] != pattern[index]) {
                    return;
                }
                index++;
            }

            if (index == pattern.size()) {
                collectSuffixIndices(node, indices);
            } else {
                for (auto it : node->children) {
                    traverseAndSearch(it.second, pattern, index, indices);
                }
            }
        }
    }

public:
    SuffixTree(const string& str) : text(str) {
        buildSuffixTree();
    }

    vector<int> search(const string& pattern) {
        vector<int> indices;
        if (pattern.empty()) {
            throw invalid_argument("Query cannot be empty");
        }

        traverseAndSearch(root, pattern, 0, indices);
        return indices;
    }
};

int main() {
    try {
        string text;
        cout << "Enter the text: ";
        getline(cin, text);

        if (text.empty()) {
            throw invalid_argument("Text cannot be empty");
        }

        SuffixTree st(text);

        string query;
        cout << "Enter the substring to search: ";
        getline(cin, query);

        vector<int> occurrences = st.search(query);

        if (occurrences.empty()) {
            cout << "Substring not found." << endl;
        } else {
            cout << "Substring found at positions: ";
            for (int pos : occurrences) {
                cout << pos << " ";
            }
            cout << endl;
        }
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << endl;
        return 1;
    }

    return 0;
}
