void max_heapify(double *heap, int size, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < size && heap[left] > heap[largest])
        largest = left;
    if (right < size && heap[right] > heap[largest])
        largest = right;
    if (largest != i) {
        swap(&heap[i], &heap[largest]);
        max_heapify(heap, size, largest);
    }
}

void min_heapify(double *heap, int size, int i) {
    int smallest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < size && heap[left] < heap[smallest])
        smallest = left;
    if (right < size && heap[right] < heap[smallest])
        smallest = right;
    if (smallest != i) {
        swap(&heap[i], &heap[smallest]);
        min_heapify(heap, size, smallest);
    }
}

void add_number(double num) {
    pthread_mutex_lock(&mf.heap_lock);

    if (mf.max_size == 0 || num <= mf.max_heap[0]) {
        mf.max_heap[mf.max_size++] = num;
        for (int i = mf.max_size / 2 - 1; i >= 0; i--)
            max_heapify(mf.max_heap, mf.max_size, i);
    } else {
        mf.min_heap[mf.min_size++] = num;
        for (int i = mf.min_size / 2 - 1; i >= 0; i--)
            min_heapify(mf.min_heap, mf.min_size, i);
    }

    // Balance heaps
    if (mf.max_size > mf.min_size + 1) {
        double temp = mf.max_heap[0];
        mf.max_heap[0] = mf.max_heap[--mf.max_size];
        max_heapify(mf.max_heap, mf.max_size, 0);
        mf.min_heap[mf.min_size++] = temp;
        for (int i = mf.min_size / 2 - 1; i >= 0; i--)
            min_heapify(mf.min_heap, mf.min_size, i);
    } else if (mf.min_size > mf.max_size) {
        double temp = mf.min_heap[0];
        mf.min_heap[0] = mf.min_heap[--mf.min_size];
        min_heapify(mf.min_heap, mf.min_size, 0);
        mf.max_heap[mf.max_size++] = temp;
        for (int i = mf.max_size / 2 - 1; i >= 0; i--)
            max_heapify(mf.max_heap, mf.max_size, i);
    }

    pthread_mutex_unlock(&mf.heap_lock);
}

double find_median() {
    pthread_mutex_lock(&mf.heap_lock);
    double median;
    if (mf.max_size == mf.min_size) {
        median = (mf.max_heap[0] + mf.min_heap[0]) / 2.0;
    } else {
        median = mf.max_heap[0];
    }
    pthread_mutex_unlock(&mf.heap_lock);
    return median;
}

