class LongestCommonSubsequence {
    constructor() {
        this.memo = new Map();
    }

    // Helper function to validate inputs
    validateInputs(word1, word2) {
        if (typeof word1 !== 'string' || typeof word2 !== 'string') {
            throw new Error('Both inputs must be strings.');
        }
        if (word1.length === 0 || word2.length === 0) {
            throw new Error('Input strings cannot be empty.');
        }
    }

    // Function to find the LCS using dynamic programming with memoization
    findLCS(word1, word2) {
        this.validateInputs(word1, word2);
        return this.lcsHelper(word1, word2, 0, 0);
    }

    lcsHelper(word1, word2, i, j) {
        const key = `${i},${j}`;
        if (this.memo.has(key)) {
            return this.memo.get(key);
        }

        if (i === word1.length || j === word2.length) {
            return '';
        }

        if (word1[i] === word2[j]) {
            const result = word1[i] + this.lcsHelper(word1, word2, i + 1, j + 1);
            this.memo.set(key, result);
            return result;
        } else {
            const lcs1 = this.lcsHelper(word1, word2, i + 1, j);
            const lcs2 = this.lcsHelper(word1, word2, i, j + 1);
            const result = lcs1.length > lcs2.length ? lcs1 : lcs2;
            this.memo.set(key, result);
            return result;
        }
    }
}

// Example usage:
try {
    const lcsFinder = new LongestCommonSubsequence();
    const word1 = "ABCBDAB";
    const word2 = "BDCABA";
    const result = lcsFinder.findLCS(word1, word2);
    console.log("Longest Common Subsequence:", result);
} catch (error) {
    console.error("Error:", error.message);
}
