using namespace std;

struct Book {
    string title;
    string author;
    int edition;
    int year;

    bool operator<(const Book& other) const {
        if (title != other.title) {
            return title < other.title;
        }
        return edition < other.edition;
    }

    bool operator==(const Book& other) const {
        return title == other.title && edition == other.edition;
    }
};

class Library {
private:
    vector<Book> books;

    bool isSorted() {
        for (size_t i = 1; i < books.size(); ++i) {
            if (books[i] < books[i-1]) {
                return false;
            }
        }
        return true;
    }

    void ensureSorted() {
        if (!isSorted()) {
            sort(books.begin(), books.end());
        }
    }

public:
    void addBook(const Book& book) {
        if (book.title.empty() || book.author.empty() || book.edition <= 0 || book.year <= 0) {
            throw invalid_argument("Invalid book data");
        }

        auto it = lower_bound(books.begin(), books.end(), book);
        if (it != books.end() && *it == book) {
            throw invalid_argument("Book with same title and edition already exists");
        }
        books.insert(it, book);
    }

    void removeBook(const string& title, int edition) {
        Book temp{title, "", edition, 0};
        auto it = lower_bound(books.begin(), books.end(), temp);
        if (it != books.end() && it->title == title && it->edition == edition) {
            books.erase(it);
        } else {
            throw invalid_argument("Book not found");
        }
    }

    vector<Book> searchByTitle(const string& title) {
        ensureSorted();
        vector<Book> result;

        Book temp{title, "", 0, 0};
        auto range = equal_range(books.begin(), books.end(), temp,
            [](const Book& a, const Book& b) {
                return a.title < b.title;
            });

        for (auto it = range.first; it != range.second; ++it) {
            result.push_back(*it);
        }

        return result;
    }

    void listAllBooks() {
        ensureSorted();
        for (const auto& book : books) {
            cout << "Title: " << book.title 
                 << ", Author: " << book.author 
                 << ", Edition: " << book.edition 
                 << ", Year: " << book.year << endl;
        }
    }
};

