#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <math.h>

#define MAX_SENSORS 10
#define WINDOW_SIZE 600 // 10 minutes in seconds (assuming 1 reading per second)
#define THRESHOLD 5.0 // Temperature difference threshold for error detection

typedef struct {
    double temperature;
    time_t timestamp;
} DataPoint;

typedef struct {
    DataPoint buffer[WINDOW_SIZE];
    int head;
    int count;
    double sum;
} MovingAverage;

void initMovingAverage(MovingAverage *ma) {
    ma->head = 0;
    ma->count = 0;
    ma->sum = 0.0;
    for (int i = 0; i < WINDOW_SIZE; i++) {
        ma->buffer[i].temperature = 0.0;
        ma->buffer[i].timestamp = 0;
    }
}

double handleDataPoint(MovingAverage *ma, double newTemp, time_t timestamp) {
    // Error checking: detect sudden spikes/drops
    if (ma->count > 0) {
        double lastTemp = ma->buffer[(ma->head - 1 + WINDOW_SIZE) % WINDOW_SIZE].temperature;
        if (fabs(newTemp - lastTemp) > THRESHOLD) {
            // Apply correction: use last valid temperature
            newTemp = lastTemp;
        }
    }

    // Remove old data points if window is full
    if (ma->count == WINDOW_SIZE) {
        ma->sum -= ma->buffer[ma->head].temperature;
        ma->count--;
    }

    // Add new data point
    ma->buffer[ma->head].temperature = newTemp;
    ma->buffer[ma->head].timestamp = timestamp;
    ma->sum += newTemp;
    ma->head = (ma->head + 1) % WINDOW_SIZE;
    ma->count++;

    // Calculate moving average
    return ma->sum / ma->count;
}

int main() {
    MovingAverage sensors[MAX_SENSORS];
    for (int i = 0; i < MAX_SENSORS; i++) {
        initMovingAverage(&sensors[i]);
    }

    // Simulate real-time data processing
    while (1) {
        for (int i = 0; i < MAX_SENSORS; i++) {
            // In a real implementation, you would get actual sensor data here
            double temp = 20.0 + (rand() % 100) / 10.0; // Simulated temperature
            time_t now = time(NULL);

            double avg = handleDataPoint(&sensors[i], temp, now);
            printf("Sensor %d: Current=%.2f, 10-min Avg=%.2f\n", i, temp, avg);
        }
        sleep(1); // Simulate 1-second interval between readings
    }

    return 0;
}
