class BTreeNode {
    constructor(degree, isLeaf) {
        this.degree = degree;
        this.isLeaf = isLeaf;
        this.keys = [];
        this.children = [];
        this.values = [];
    }
}

class BTree {
    constructor(degree = 2) {
        this.root = null;
        this.degree = degree;
    }

    search(key) {
        return this._search(this.root, key);
    }

    _search(node, key) {
        let i = 0;
        while (i < node.keys.length && key > node.keys[i]) {
            i++;
        }
        if (i < node.keys.length && key === node.keys[i]) {
            return node.values[i];
        }
        if (node.isLeaf) {
            return null;
        }
        return this._search(node.children[i], key);
    }

    insert(key, value) {
        if (this.root === null) {
            this.root = new BTreeNode(this.degree, true);
            this.root.keys.push(key);
            this.root.values.push(value);
            return;
        }
        if (this.root.keys.length === 2 * this.degree - 1) {
            const newRoot = new BTreeNode(this.degree, false);
            newRoot.children.push(this.root);
            this._splitChild(newRoot, 0, this.root);
            this.root = newRoot;
            this._insertNonFull(this.root, key, value);
        } else {
            this._insertNonFull(this.root, key, value);
        }
    }

    _insertNonFull(node, key, value) {
        let i = node.keys.length - 1;
        if (node.isLeaf) {
            while (i >= 0 && key < node.keys[i]) {
                i--;
            }
            if (i >= 0 && key === node.keys[i]) {
                throw new Error("Duplicate key detected");
            }
            node.keys.splice(i + 1, 0, key);
            node.values.splice(i + 1, 0, value);
        } else {
            while (i >= 0 && key < node.keys[i]) {
                i--;
            }
            i++;
            if (node.children[i].keys.length === 2 * this.degree - 1) {
                this._splitChild(node, i, node.children[i]);
                if (key > node.keys[i]) {
                    i++;
                }
            }
            this._insertNonFull(node.children[i], key, value);
        }
    }

    _splitChild(parent, index, child) {
        const newChild = new BTreeNode(child.degree, child.isLeaf);
        parent.keys.splice(index, 0, child.keys[this.degree - 1]);
        parent.values.splice(index, 0, child.values[this.degree - 1]);
        parent.children.splice(index + 1, 0, newChild);
        newChild.keys = child.keys.slice(this.degree);
        newChild.values = child.values.slice(this.degree);
        child.keys = child.keys.slice(0, this.degree - 1);
        child.values = child.values.slice(0, this.degree - 1);
        if (!child.isLeaf) {
            newChild.children = child.children.slice(this.degree);
            child.children = child.children.slice(0, this.degree);
        }
    }

    delete(key) {
        if (this.root === null) {
            throw new Error("Tree is empty");
        }
        this._delete(this.root, key);
        if (this.root.keys.length === 0 && !this.root.isLeaf) {
            this.root = this.root.children[0];
        }
    }

    _delete(node, key) {
        let i = 0;
        while (i < node.keys.length && key > node.keys[i]) {
            i++;
        }
        if (i < node.keys.length && key === node.keys[i]) {
            if (node.isLeaf) {
                node.keys.splice(i, 1);
                node.values.splice(i, 1);
            } else {
                this._deleteFromNonLeaf(node, i);
            }
        } else {
            if (node.isLeaf) {
                throw new Error("Key not found");
            }
            const flag = i === node.keys.length;
            if (node.children[i].keys.length < this.degree) {
                this._fill(node, i);
            }
            if (flag && i > node.keys.length) {
                this._delete(node.children[i - 1], key);
            } else {
                this._delete(node.children[i], key);
            }
        }
    }

    _deleteFromNonLeaf(node, index) {
        const key = node.keys[index];
        if (node.children[index].keys.length >= this.degree) {
            const pred = this._getPredecessor(node.children[index]);
            node.keys[index] = pred.key;
            node.values[index] = pred.value;
            this._delete(node.children[index], pred.key);
        } else if (node.children[index + 1].keys.length >= this.degree) {
            const succ = this._getSuccessor(node.children[index + 1]);
            node.keys[index] = succ.key;
            node.values[index] = succ.value;
            this._delete(node.children[index + 1], succ.key);
        } else {
            this._merge(node, index);
            this._delete(node.children[index], key);
        }
    }

    _getPredecessor(node) {
        while (!node.isLeaf) {
            node = node.children[node.keys.length];
        }
        return { key: node.keys[node.keys.length - 1], value: node.values[node.values.length - 1] };
    }

    _getSuccessor(node) {
        while (!node.isLeaf) {
            node = node.children[0];
        }
        return { key: node.keys[0], value: node.values[0] };
    }

    _fill(node, index) {
        if (index !== 0 && node.children[index - 1].keys.length >= this.degree) {
            this._borrowFromPrev(node, index);
        } else if (index !== node.keys.length && node.children[index + 1].keys.length >= this.degree) {
            this._borrowFromNext(node, index);
        } else {
            if (index !== node.keys.length) {
                this._merge(node, index);
            } else {
                this._merge(node, index - 1);
            }
        }
    }

    _borrowFromPrev(node, index) {
        const child = node.children[index];
        const sibling = node.children[index - 1];
        child.keys.unshift(node.keys[index - 1]);
        child.values.unshift(node.values[index - 1]);
        if (!child.isLeaf) {
            child.children.unshift(sibling.children[sibling.children.length - 1]);
            sibling.children.pop();
        }
        node.keys[index - 1] = sibling.keys.pop();
        node.values[index - 1] = sibling.values.pop();
    }

    _borrowFromNext(node, index) {
        const child = node.children[index];
        const sibling = node.children[index + 1];
        child.keys.push(node.keys[index]);
        child.values.push(node.values[index]);
        if (!child.isLeaf) {
            child.children.push(sibling.children[0]);
            sibling.children.shift();
        }
        node.keys[index] = sibling.keys.shift();
        node.values[index] = sibling.values.shift();
    }

    _merge(node, index) {
        const child = node.children[index];
        const sibling = node.children[index + 1];
        child.keys.push(node.keys[index]);
        child.values.push(node.values[index]);
        for (let i = 0; i < sibling.keys.length; i++) {
            child.keys.push(sibling.keys[i]);
            child.values.push(sibling.values[i]);
        }
        if (!child.isLeaf) {
            for (let i = 0; i < sibling.children.length; i++) {
                child.children.push(sibling.children[i]);
            }
        }
        node.keys.splice(index, 1);
        node.values.splice(index, 1);
        node.children.splice(index + 1, 1);
    }
}

class BookCatalog {
    constructor() {
        this.tree = new BTree(2);
    }

    loadFromJSON(jsonData) {
        try {
            const data = typeof jsonData === 'string' ? JSON.parse(jsonData) : jsonData;
            if (!Array.isArray(data)) {
