#include <iostream>
#include <fstream>
#include <string>
#include <unordered_map>
#include <vector>
#include <algorithm>
#include <queue>
#include <stdexcept>

class UserActivityAnalyzer {
private:
    std::unordered_map<std::string, int> user_activity;
    std::priority_queue<std::pair<int, std::string>> max_heap;

public:
    void processLogFile(const std::string& file_path) {
        std::ifstream file(file_path);
        if (!file.is_open()) {
            throw std::runtime_error("Failed to open file: " + file_path);
        }

        std::string line;
        while (getline(file, line)) {
            try {
                size_t delimiter_pos = line.find(',');
                if (delimiter_pos == std::string::npos) {
                    continue; // Skip malformed lines
                }

                std::string user_id = line.substr(0, delimiter_pos);
                int activity_count = std::stoi(line.substr(delimiter_pos + 1));
                user_activity[user_id] += activity_count;
            } catch (...) {
                // Skip lines with data corruption
                continue;
            }
        }
        file.close();
    }

    void updateUserActivity(const std::string& user_id, int activity_count) {
        user_activity[user_id] += activity_count;
    }

    std::vector<std::pair<std::string, int>> getTopKUsers(int k) {
        // Clear previous heap
        max_heap = std::priority_queue<std::pair<int, std::string>>();

        // Build max heap (O(n) time)
        for (const auto& entry : user_activity) {
            max_heap.emplace(entry.second, entry.first);
        }

        // Extract top k elements (O(k log n) time)
        std::vector<std::pair<std::string, int>> result;
        for (int i = 0; i < k && !max_heap.empty(); ++i) {
            auto top = max_heap.top();
            result.emplace_back(top.second, top.first);
            max_heap.pop();
        }

        return result;
    }
