use std::io;

fn is_safe(board: &Vec<Vec<bool>>, row: usize, col: usize) -> bool {
    // Check left side of the row
    for i in 0..col {
        if board[row][i] {
            return false;
        }
    }

    // Check upper diagonal on left side
    let mut i = row as i32;
    let mut j = col as i32;
    while i >= 0 && j >= 0 {
        if board[i as usize][j as usize] {
            return false;
        }
        i -= 1;
        j -= 1;
    }

    // Check lower diagonal on left side
    let mut i = row;
    let mut j = col as i32;
    while i < board.len() && j >= 0 {
        if board[i][j as usize] {
            return false;
        }
        i += 1;
        j -= 1;
    }

    true
}

fn solve_n_queens_util(board: &mut Vec<Vec<bool>>, col: usize, solutions: &mut Vec<Vec<Vec<bool>>>) {
    if col >= board.len() {
        solutions.push(board.clone());
        return;
    }

    for row in 0..board.len() {
        if is_safe(board, row, col) {
            board[row][col] = true;
            solve_n_queens_util(board, col + 1, solutions);
            board[row][col] = false;
        }
    }
}

fn solve_n_queens(n: usize) -> Vec<Vec<Vec<bool>>> {
    let mut board = vec![vec![false; n]; n];
    let mut solutions = Vec::new();
    solve_n_queens_util(&mut board, 0, &mut solutions);
    solutions
}

fn print_solutions(solutions: &Vec<Vec<Vec<bool>>>) {
    for (i, solution) in solutions.iter().enumerate() {
        println!("Solution {}:", i + 1);
        for row in solution {
            for &cell in row {
                print!("{} ", if cell { "Q" } else { "." });
            }
            println!();
        }
        println!();
    }
}

fn main() {
    println!("Enter the number of queens (board size):");
    let mut input = String::new();
    io::stdin().read_line(&mut input).expect("Failed to read input");
    let n: usize = input.trim().parse().expect("Please enter a valid number");

    if n < 1 {
        println!("Board size must be at least 1.");
        return;
    }

    let solutions = solve_n_queens(n);

    if solutions.is_empty() {
        println!("No solutions exist for a {}x{} board.", n, n);
    } else {
        println!("Found {} solutions:", solutions.len());
        print_solutions(&solutions);
    }
}
