import sys
from collections import defaultdict

class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return False
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        return True

def read_input(filename):
    cities = []
    edges = []
    city_indices = {}
    with open(filename, 'r') as file:
        for line in file:
            parts = line.strip().split()
            if len(parts) < 3:
                continue
            city1, city2, distance = parts[0], parts[1], float(parts[2])
            if city1 not in city_indices:
                city_indices[city1] = len(cities)
                cities.append(city1)
            if city2 not in city_indices:
                city_indices[city2] = len(cities)
                cities.append(city2)
            edges.append((city_indices[city1], city_indices[city2], distance))
    return cities, edges

def kruskal_mst(cities, edges):
    edges.sort(key=lambda x: x[2])
    uf = UnionFind(len(cities))
    mst = []
    for u, v, weight in edges:
        if uf.union(u, v):
            mst.append((u, v, weight))
    return mst

def main():
    if len(sys.argv) != 2:
        print("Usage: python kruskal.py <input_file>")
        return
    input_file = sys.argv[1]
    cities, edges = read_input(input_file)
    if not cities or not edges:
        print("No valid input data found.")
        return
    mst = kruskal_mst(cities, edges)
    print("Minimum Spanning Tree:")
    for u, v, weight in mst:
        print(f"{cities[u]} -- {cities[v]} : {weight}")

if __name__ == "__main__":
    main()
