use std::collections::HashMap;

#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            children: HashMap::new(),
            is_end_of_word: false,
        }
    }
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::new(),
        }
    }

    fn insert(&mut self, word: &str) -> Result<(), String> {
        if word.is_empty() {
            return Err("Empty query cannot be inserted".to_string());
        }

        let mut current = &mut self.root;
        for ch in word.chars() {
            current = current.children.entry(ch).or_insert_with(TrieNode::new);
        }
        current.is_end_of_word = true;
        Ok(())
    }

    fn search(&self, prefix: &str) -> Result<Vec<String>, String> {
        if prefix.is_empty() {
            return Err("Empty prefix cannot be searched".to_string());
        }

        let mut current = &self.root;
        for ch in prefix.chars() {
            if let Some(node) = current.children.get(&ch) {
                current = node;
            } else {
                return Ok(vec![]);
            }
        }
        Ok(self.collect_words(current, prefix))
    }

    fn collect_words(&self, node: &TrieNode, prefix: &str) -> Vec<String> {
        let mut words = Vec::new();
        if node.is_end_of_word {
            words.push(prefix.to_string());
        }
        for (ch, child_node) in &node.children {
            let new_prefix = format!("{}{}", prefix, ch);
            words.extend(self.collect_words(child_node, &new_prefix));
        }
        words
    }
}

fn main() {
    let mut trie = Trie::new();

    // Example usage
    let queries = vec!["rust", "ruby", "python", "java", "javascript"];
    for query in queries {
        trie.insert(query).unwrap();
    }

    println!("Suggestions for 'ru': {:?}", trie.search("ru").unwrap());
    println!("Suggestions for 'jav': {:?}", trie.search("jav").unwrap());
    println!("Suggestions for 'go': {:?}", trie.search("go").unwrap());
}
