const fs = require('fs');

class SuffixTreeNode {
    constructor() {
        this.children = {};
        this.indexes = [];
    }
}

class SuffixTree {
    constructor(str) {
        this.root = new SuffixTreeNode();
        this.str = str;
        this.buildSuffixTree();
    }

    buildSuffixTree() {
        for (let i = 0; i < this.str.length; i++) {
            this.insertSuffix(this.str.substring(i), i);
        }
    }

    insertSuffix(suffix, index) {
        let node = this.root;
        for (let char of suffix) {
            if (!node.children[char]) {
                node.children[char] = new SuffixTreeNode();
            }
            node = node.children[char];
            node.indexes.push(index);
        }
    }

    findLongestRepeatedSubstring() {
        let result = { length: 0, substring: '' };
        this.traverse(this.root, '', result);
        return result.substring;
    }

    traverse(node, current, result) {
        if (Object.keys(node.children).length === 0) return;

        for (let [char, child] of Object.entries(node.children)) {
            if (child.indexes.length >= 2) {
                const newCurrent = current + char;
                if (newCurrent.length > result.length) {
                    result.length = newCurrent.length;
                    result.substring = newCurrent;
                }
                this.traverse(child, newCurrent, result);
            }
        }
    }
}

function findLongestRepeatedSubstringFromFile(filePath) {
    try {
        const data = fs.readFileSync(filePath, 'utf8');
        if (!data.trim()) {
            throw new Error('File is empty');
        }

        const suffixTree = new SuffixTree(data);
        const longestSubstring = suffixTree.findLongestRepeatedSubstring();

        return longestSubstring || 'No repeated substring found';
    } catch (error) {
        if (error.code === 'ENOENT') {
            return 'Error: File not found';
        } else if (error.message === 'File is empty') {
            return 'Error: File is empty';
        } else {
            return `Error: ${error.message}`;
        }
    }
}

