import java.util.Scanner;

class Song {
    String title;
    Song prev;
    Song next;

    public Song(String title) {
        this.title = title;
        this.prev = null;
        this.next = null;
    }
}

class Playlist {
    private Song head;
    private Song tail;

    public Playlist() {
        this.head = null;
        this.tail = null;
    }

    public boolean isEmpty() {
        return head == null;
    }

    public void addSong(String title) {
        if (title == null || title.trim().isEmpty()) {
            System.out.println("Invalid song title.");
            return;
        }

        Song newSong = new Song(title);
        if (isEmpty()) {
            head = newSong;
            tail = newSong;
        } else {
            Song current = head;
            while (current != null) {
                if (current.title.equalsIgnoreCase(title)) {
                    System.out.println("Song '" + title + "' already exists in the playlist.");
                    return;
                }
                current = current.next;
            }
            tail.next = newSong;
            newSong.prev = tail;
            tail = newSong;
        }
        System.out.println("Song '" + title + "' added to the playlist.");
    }

    public void removeSong(String title) {
        if (isEmpty()) {
            System.out.println("Playlist is empty.");
            return;
        }

        Song current = head;
        while (current != null) {
            if (current.title.equalsIgnoreCase(title)) {
                if (current == head && current == tail) {
                    head = null;
                    tail = null;
                } else if (current == head) {
                    head = head.next;
                    head.prev = null;
                } else if (current == tail) {
                    tail = tail.prev;
                    tail.next = null;
                } else {
                    current.prev.next = current.next;
                    current.next.prev = current.prev;
                }
                System.out.println("Song '" + title + "' removed from the playlist.");
                return;
            }
            current = current.next;
        }
        System.out.println("Song '" + title + "' not found in the playlist.");
    }

    public void moveSong(String title, int newPosition) {
        if (isEmpty()) {
            System.out.println("Playlist is empty.");
            return;
        }

        if (newPosition < 1) {
            System.out.println("Invalid position.");
            return;
        }

        Song songToMove = null;
        Song current = head;
        while (current != null) {
            if (current.title.equalsIgnoreCase(title)) {
                songToMove = current;
                break;
            }
            current = current.next;
        }

        if (songToMove == null) {
            System.out.println("Song '" + title + "' not found in the playlist.");
            return;
        }

        // Remove the song from its current position
        if (songToMove == head && songToMove == tail) {
            head = null;
            tail = null;
        } else if (songToMove == head) {
            head = head.next;
            head.prev = null;
        } else if (songToMove == tail) {
            tail = tail.prev;
            tail.next = null;
        } else {
            songToMove.prev.next = songToMove.next;
            songToMove.next.prev = songToMove.prev;
        }

        // Insert the song at the new position
        if (isEmpty()) {
            head = songToMove;
            tail = songToMove;
            songToMove.prev = null;
            songToMove.next = null;
        } else {
            current = head;
            int count = 1;
            while (count < newPosition && current.next != null) {
                current = current.next;
                count++;
            }

            if (newPosition == 1) {
                songToMove.next = head;
                songToMove.prev = null;
                head.prev = songToMove;
                head = songToMove;
            } else if (current == tail && count < newPosition) {
                tail.next = songToMove;
                songToMove.prev = tail;
                songToMove.next = null;
                tail = songToMove;
            } else {
                songToMove.prev = current.prev;
                songToMove.next = current;
                current.prev.next = songToMove;
                current.prev = songToMove;
            }
        }
        System.out.println("Song '" + title + "' moved to position " + newPosition + ".");
    }

    public void searchSong(String title) {
        if (isEmpty()) {
            System.out.println("Playlist is empty.");
            return;
        }

        Song current = head;
        int position = 1;
        boolean found = false;
        while (current != null) {
            if (current.title.equalsIgnoreCase(title)) {
                System.out.println("Song '" + title + "' found at position " + position + ".");
                found = true;
                break;
            }
            current = current.next;
            position++;
        }

        if (!found) {
            System.out.println("Song '" + title + "' not found in the playlist.");
        }
    }

    public void displayPlaylist() {
        if (isEmpty()) {
            System.out.println("Playlist is empty.");
            return;
        }

        Song current = head;
        int position = 1;
        System.out.println("Current Playlist:");
        while (current != null) {
            System.out.println(position + ". " + current.title);
            current = current.next;
            position++;
        }
    }
}

