#include <iostream>
#include <vector>
#include <stdexcept>

using namespace std;

class NQueens {
private:
    int n;
    vector<vector<int>> board;
    vector<vector<vector<int>>> solutions;

    bool isSafe(int row, int col) {
        // Check left side of the row
        for (int i = 0; i < col; ++i) {
            if (board[row][i] == 1) {
                return false;
            }
        }

        // Check upper diagonal on left side
        for (int i = row, j = col; i >= 0 && j >= 0; --i, --j) {
            if (board[i][j] == 1) {
                return false;
            }
        }

        // Check lower diagonal on left side
        for (int i = row, j = col; i < n && j >= 0; ++i, --j) {
            if (board[i][j] == 1) {
                return false;
            }
        }

        return true;
    }

    void solveNQueensUtil(int col) {
        if (col == n) {
            solutions.push_back(board);
            return;
        }

        for (int i = 0; i < n; ++i) {
            if (isSafe(i, col)) {
                board[i][col] = 1;
                solveNQueensUtil(col + 1);
                board[i][col] = 0; // Backtrack
            }
        }
    }

public:
    NQueens(int size) : n(size) {
        if (n <= 0) {
            throw invalid_argument("Board size must be positive.");
        }
        board.resize(n, vector<int>(n, 0));
    }

    void solve() {
        solutions.clear();
        solveNQueensUtil(0);
    }

    void printSolutions() {
        if (solutions.empty()) {
            cout << "No solutions found for " << n << "-Queens problem." << endl;
            return;
        }

        cout << "Found " << solutions.size() << " solutions for " << n << "-Queens problem:" << endl;
        for (const auto &sol : solutions) {
            for (const auto &row : sol) {
                for (int val : row) {
                    cout << (val == 1 ? "Q " : ". ");
                }
                cout << endl;
            }
            cout << endl;
        }
    }
};

int main() {
    try {
        NQueens nq(8);
        nq.solve();
        nq.printSolutions();
    } catch (const exception &e) {
        cerr << "Error: " << e.what() << endl;
        return 1;
    }
    return 0;
}
