            int[] gaps2 = {5, 3, 1}; // Simple gap sequence

            shellSort(salaries, gaps1);
            System.out.println("Sorted with Ciura gaps: " + salaries);

            shellSort(salaries, gaps2);
            System.out.println("Sorted with simple gaps: " + salaries);
        }
