    public static List<Integer> readSalariesFromCSV(String csvFile) {
        List<Integer> salaries = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] data = line.split(",");
                for (String value : data) {
                    try {
                        int salary = Integer.parseInt(value.trim());
                        if (salary > 0) {
                            salaries.add(salary);
                        } else {
                            System.err.println("Invalid salary (must be positive): " + salary);
                        }
                    } catch (NumberFormatException e) {
                        System.err.println("Invalid salary format: " + value);
                    }
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
            return null;
        }
        return salaries;
    }

    public static void shellSort(List<Integer> list, int[] gaps) {
        for (int gap : gaps) {
            for (int i = gap; i < list.size(); i++) {
                int temp = list.get(i);
                int j;
                for (j = i; j >= gap && list.get(j - gap) > temp; j -= gap) {
                    list.set(j, list.get(j - gap));
                }
                list.set(j, temp);
            }
        }
    }
}
