class TabHistory {
  constructor() {
    this.head = null;
    this.tail = null;
    this.current = null;
  }

  // Node class for doubly linked list
  static Node = class {
    constructor(url) {
      this.url = url;
      this.prev = null;
      this.next = null;
    }
  };

  // Open a new tab (clears forward history)
  open(url) {
    const newNode = new TabHistory.Node(url);
    if (!this.head) {
      this.head = newNode;
      this.tail = newNode;
    } else {
      newNode.prev = this.current;
      this.current.next = newNode;
      // Clear forward history
      let node = newNode.next;
      while (node) {
        const nextNode = node.next;
        node.prev = null;
        node.next = null;
        node = nextNode;
      }
      this.tail = newNode;
    }
    this.current = newNode;
  }

  // Close current tab
  close() {
    if (!this.current) return false;

    if (this.current === this.head && this.current === this.tail) {
      this.head = null;
      this.tail = null;
      this.current = null;
    } else if (this.current === this.head) {
      this.head = this.current.next;
      this.head.prev = null;
      this.current = this.head;
    } else if (this.current === this.tail) {
      this.tail = this.current.prev;
      this.tail.next = null;
      this.current = this.tail;
    } else {
      this.current.prev.next = this.current.next;
      this.current.next.prev = this.current.prev;
      this.current = this.current.next;
    }
    return true;
  }

  // Navigate backward
  back() {
    if (!this.current || !this.current.prev) return false;
    this.current = this.current.prev;
    return true;
  }

  // Navigate forward
  forward() {
    if (!this.current || !this.current.next) return false;
    this.current = this.current.next;
    return true;
  }

  // Get current URL
  getCurrent() {
    return this.current ? this.current.url : null;
  }
}
