struct Student {
    std::string name;
    double gpa;
};

void readStudentRecords(const std::string& filename, std::vector<Student>& students) {
    std::ifstream file(filename);
    if (!file.is_open()) {
        throw std::runtime_error("Failed to open file.");
    }

    std::string line;
    while (std::getline(file, line)) {
        try {
            size_t comma_pos = line.find(',');
            if (comma_pos == std::string::npos) {
                continue; // Skip invalid lines
            }

            std::string name = line.substr(0, comma_pos);
            double gpa = std::stod(line.substr(comma_pos + 1));
            students.push_back({name, gpa});
        } catch (...) {
            continue; // Skip lines with invalid GPA format
        }
    }

    file.close();
}

void selectionSortDescending(std::vector<Student>& students) {
    for (size_t i = 0; i < students.size() - 1; ++i) {
        size_t max_idx = i;
        for (size_t j = i + 1; j < students.size(); ++j) {
            if (students[j].gpa > students[max_idx].gpa) {
                max_idx = j;
            }
        }
        if (max_idx != i) {
            std::swap(students[i], students[max_idx]);
        }
    }
}

void printStudents(const std::vector<Student>& students) {
    for (const auto& student : students) {
        std::cout << std::left << std::setw(30) << student.name 
                  << std::fixed << std::setprecision(2) << student.gpa << std::endl;
    }
}

