class Dictionary {
    constructor() {
        this.words = {};
    }

    // Perfect hash function using built-in JavaScript hashing
    _hash(word) {
        return word.toLowerCase(); // Case-insensitive lookup
    }

    // Add a word with its definition
    addWord(word, definition) {
        const key = this._hash(word);
        if (this.words[key] !== undefined) {
            console.warn(`Warning: '${word}' already exists. Overwriting definition.`);
        }
        this.words[key] = definition;
    }

    // Delete a word from the dictionary
    deleteWord(word) {
        const key = this._hash(word);
        if (this.words[key] === undefined) {
            console.warn(`Warning: '${word}' not found in dictionary.`);
            return false;
        }
        delete this.words[key];
        return true;
    }

    // Query a word's definition
    lookupWord(word) {
        const key = this._hash(word);
        if (this.words[key] === undefined) {
            console.warn(`Warning: '${word}' not found in dictionary.`);
            return null;
        }
        return this.words[key];
    }
}

