import java.util.*;

class Player implements Comparable<Player> {
    String id;
    int score;

    public Player(String id, int score) {
        this.id = id;
        this.score = score;
    }

    @Override
    public int compareTo(Player other) {
        return Integer.compare(other.score, this.score); // Descending order
    }
}

public class Leaderboard {
    private TreeSet<Player> players;
    private Map<String, Player> playerMap;

    public Leaderboard() {
        players = new TreeSet<>();
        playerMap = new HashMap<>();
    }

    public void insertOrUpdate(String playerId, int score) {
        if (playerMap.containsKey(playerId)) {
            Player oldPlayer = playerMap.get(playerId);
            players.remove(oldPlayer);
        }
        Player newPlayer = new Player(playerId, score);
        players.add(newPlayer);
        playerMap.put(playerId, newPlayer);
    }

    public void delete(String playerId) {
        if (playerMap.containsKey(playerId)) {
            Player player = playerMap.get(playerId);
            players.remove(player);
            playerMap.remove(playerId);
        }
    }

    public int getKthHighest(int k) {
        if (k < 1 || k > players.size()) {
            throw new IllegalArgumentException("Invalid k value");
        }
        Iterator<Player> iterator = players.iterator();
        Player result = null;
        for (int i = 0; i < k; i++) {
            result = iterator.next();
        }
        return result.score;
    }

    public static void main(String[] args) {
        Leaderboard leaderboard = new Leaderboard();
        leaderboard.insertOrUpdate("player1", 100);
        leaderboard.insertOrUpdate("player2", 200);
        leaderboard.insertOrUpdate("player3", 50);
        System.out.println("2nd highest: " + leaderboard.getKthHighest(2)); // 100
        leaderboard.delete("player1");
        System.out.println("2nd highest after deletion: " + leaderboard.getKthHighest(2)); // 50
    }
}
