#include <iostream>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <limits>
#include <string>

using namespace std;

class Stock {
public:
    string symbol;
    double price;

    Stock(string s, double p) : symbol(s), price(p) {}

    bool operator<(const Stock& other) const {
        return price < other.price;
    }

    bool operator==(const Stock& other) const {
        return symbol == other.symbol;
    }
};

class SkipListNode {
public:
    Stock stock;
    vector<SkipListNode*> forward;

    SkipListNode(Stock s, int level) : stock(s), forward(level + 1, nullptr) {}
};

class SkipList {
private:
    SkipListNode* header;
    int maxLevel;
    float probability;
    int currentLevel;

    int randomLevel() {
        int level = 0;
        while (static_cast<float>(rand()) / RAND_MAX < probability && level < maxLevel) {
            level++;
        }
        return level;
    }

public:
    SkipList(int maxLvl = 16, float p = 0.5) : maxLevel(maxLvl), probability(p), currentLevel(0) {
        Stock dummyStock("", numeric_limits<double>::min());
        header = new SkipListNode(dummyStock, maxLevel);
    }

    ~SkipList() {
        SkipListNode* node = header->forward[0];
        while (node != nullptr) {
            SkipListNode* next = node->forward[0];
            delete node;
            node = next;
        }
        delete header;
    }

    void insert(Stock stock) {
        vector<SkipListNode*> update(maxLevel + 1, nullptr);
        SkipListNode* current = header;

        for (int i = currentLevel; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->stock < stock) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (current == nullptr || !(current->stock == stock)) {
            int newLevel = randomLevel();

            if (newLevel > currentLevel) {
                for (int i = currentLevel + 1; i <= newLevel; i++) {
                    update[i] = header;
                }
                currentLevel = newLevel;
            }

            SkipListNode* newNode = new SkipListNode(stock, newLevel);

            for (int i = 0; i <= newLevel; i++) {
                newNode->forward[i] = update[i]->forward[i];
                update[i]->forward[i] = newNode;
            }
        }
    }

    bool remove(string symbol) {
        vector<SkipListNode*> update(maxLevel + 1, nullptr);
        SkipListNode* current = header;

        for (int i = currentLevel; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->stock.symbol < symbol) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (current != nullptr && current->stock.symbol == symbol) {
            for (int i = 0; i <= currentLevel; i++) {
                if (update[i]->forward[i] != current) {
                    break;
                }
                update[i]->forward[i] = current->forward[i];
            }

            delete current;

            while (currentLevel > 0 && header->forward[currentLevel] == nullptr) {
                currentLevel--;
            }

            return true;
        }
        return false;
    }

    double search(string symbol) {
        SkipListNode* current = header;

        for (int i = currentLevel; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->stock.symbol < symbol) {
                current = current->forward[i];
            }
        }

        current = current->forward[0];

        if (current != nullptr && current->stock.symbol == symbol) {
            return current->stock.price;
        }
        return -1.0; // Not found
    }

    vector<Stock> getSortedStocks() {
        vector<Stock> sortedStocks;
        SkipListNode* current = header->forward[0];

        while (current != nullptr) {
            sortedStocks.push_back(current->stock);
            current = current->forward[0];
        }

        return sortedStocks;
    }
};

int main() {
    srand(time(0));
    SkipList stockList;

    // Example usage
    stockList.insert(Stock("AAPL", 150.0));
    stockList.insert(Stock("GOOGL", 2800.0));
    stockList.insert(Stock("MSFT", 300.0));

    cout << "AAPL price: " << stockList.search("AAPL") << endl;
    cout << "GOOGL price: " << stockList.search("GOOGL") << endl;

    stockList.remove("GOOGL");
    cout << "GOOGL after removal: " << stockList.search("GOOGL") << endl;

    vector<Stock> sortedStocks = stockList.getSortedStocks();
    cout << "Sorted stocks by price:" << endl;
    for (const auto& stock : sortedStocks) {
        cout << stock.symbol << ": " << stock.price << endl;
    }

    return 0;
}
