use std::cmp::Ordering;
use std::collections::BinaryHeap;

#[derive(Debug, Clone)]
struct DroneTask {
    id: u32,
    urgency: u32,
    resource_availability: u32,
    priority: u32,
}

impl DroneTask {
    fn new(id: u32, urgency: u32, resource_availability: u32) -> Self {
        let priority = urgency * resource_availability;
        DroneTask {
            id,
            urgency,
            resource_availability,
            priority,
        }
    }

    fn update_priority(&mut self, new_urgency: u32, new_resource_availability: u32) {
        self.urgency = new_urgency;
        self.resource_availability = new_resource_availability;
        self.priority = new_urgency * new_resource_availability;
    }
}

impl PartialEq for DroneTask {
    fn eq(&self, other: &Self) -> bool {
        self.priority == other.priority
    }
}

impl Eq for DroneTask {}

impl PartialOrd for DroneTask {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for DroneTask {
    fn cmp(&self, other: &Self) -> Ordering {
        self.priority.cmp(&other.priority)
    }
}

struct DroneTaskScheduler {
    task_queue: BinaryHeap<DroneTask>,
}

impl DroneTaskScheduler {
    fn new() -> Self {
        DroneTaskScheduler {
            task_queue: BinaryHeap::new(),
        }
    }

    fn insert_task(&mut self, task: DroneTask) {
        self.task_queue.push(task);
    }

    fn update_task_priority(
        &mut self,
        task_id: u32,
        new_urgency: u32,
        new_resource_availability: u32,
    ) -> bool {
        let mut found = false;
        let mut tasks: Vec<DroneTask> = self.task_queue.drain().collect();

        for task in tasks.iter_mut() {
            if task.id == task_id {
                task.update_priority(new_urgency, new_resource_availability);
                found = true;
                break;
            }
        }

        self.task_queue = tasks.into_iter().collect();
        found
    }

    fn fetch_highest_priority_task(&mut self) -> Option<DroneTask> {
        self.task_queue.pop()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_task_scheduler() {
        let mut scheduler = DroneTaskScheduler::new();
        let task1 = DroneTask::new(1, 3, 2);
        let task2 = DroneTask::new(2, 1, 5);
        let task3 = DroneTask::new(3, 4, 1);

        scheduler.insert_task(task1);
        scheduler.insert_task(task2);
        scheduler.insert_task(task3);

        assert_eq!(scheduler.fetch_highest_priority_task().unwrap().id, 3);
        assert_eq!(scheduler.fetch_highest_priority_task().unwrap().id, 1);
        assert_eq!(scheduler.fetch_highest_priority_task().unwrap().id, 2);
