class AVLNode {
    constructor(userId, score) {
        this.userId = userId;
        this.score = score;
        this.left = null;
        this.right = null;
        this.height = 1;
        this.size = 1;
    }
}

class Leaderboard {
    constructor() {
        this.root = null;
        this.userMap = new Map(); // userId -> score
    }

    getHeight(node) {
        return node ? node.height : 0;
    }

    getSize(node) {
        return node ? node.size : 0;
    }

    updateHeightAndSize(node) {
        node.height = Math.max(this.getHeight(node.left), this.getHeight(node.right)) + 1;
        node.size = this.getSize(node.left) + this.getSize(node.right) + 1;
    }

    balanceFactor(node) {
        return this.getHeight(node.left) - this.getHeight(node.right);
    }

    rotateRight(y) {
        const x = y.left;
        const T2 = x.right;

        x.right = y;
        y.left = T2;

        this.updateHeightAndSize(y);
        this.updateHeightAndSize(x);

        return x;
    }

    rotateLeft(x) {
        const y = x.right;
        const T2 = y.left;

        y.left = x;
        x.right = T2;

        this.updateHeightAndSize(x);
        this.updateHeightAndSize(y);

        return y;
    }

    insert(node, userId, score) {
        if (!node) return new AVLNode(userId, score);

        if (score < node.score) {
            node.left = this.insert(node.left, userId, score);
        } else if (score > node.score) {
            node.right = this.insert(node.right, userId, score);
        } else {
            // Handle duplicates (same score)
            node.right = this.insert(node.right, userId, score);
        }

        this.updateHeightAndSize(node);

        const balance = this.balanceFactor(node);

        // Left Left
        if (balance > 1 && score < node.left.score) {
            return this.rotateRight(node);
        }

        // Right Right
        if (balance < -1 && score > node.right.score) {
            return this.rotateLeft(node);
        }

        // Left Right
        if (balance > 1 && score > node.left.score) {
            node.left = this.rotateLeft(node.left);
            return this.rotateRight(node);
        }

        // Right Left
        if (balance < -1 && score < node.right.score) {
            node.right = this.rotateRight(node.right);
            return this.rotateLeft(node);
        }

        return node;
    }

    updateScore(userId, score) {
        const oldScore = this.userMap.get(userId);
        if (oldScore !== undefined) {
            this.root = this.delete(this.root, oldScore, userId);
        }
        this.userMap.set(userId, score);
        this.root = this.insert(this.root, userId, score);
    }

    delete(node, score, userId) {
        if (!node) return node;

        if (score < node.score) {
            node.left = this.delete(node.left, score, userId);
        } else if (score > node.score) {
            node.right = this.delete(node.right, score, userId);
        } else {
            if (node.userId === userId) {
                if (!node.left || !node.right) {
                    const temp = node.left || node.right;
                    node = temp || null;
                } else {
                    const temp = this.getMinNode(node.right);
                    node.userId = temp.userId;
                    node.score = temp.score;
                    node.right = this.delete(node.right, temp.score, temp.userId);
                }
            } else {
                node.right = this.delete(node.right, score, userId);
            }
        }

        if (!node) return node;

        this.updateHeightAndSize(node);

        const balance = this.balanceFactor(node);

        // Left Left
        if (balance > 1 && this.balanceFactor(node.left) >= 0) {
            return this.rotateRight(node);
        }

        // Left Right
        if (balance > 1 && this.balanceFactor(node.left) < 0) {
            node.left = this.rotateLeft(node.left);
            return this.rotateRight(node);
        }

        // Right Right
        if (balance < -1 && this.balanceFactor(node.right) <= 0) {
            return this.rotateLeft(node);
        }

        // Right Left
        if (balance < -1 && this.balanceFactor(node.right) > 0) {
            node.right = this.rotateRight(node.right);
            return this.rotateLeft(node);
        }

        return node;
    }

    getMinNode(node) {
        let current = node;
        while (current.left) {
            current = current.left;
        }
        return current;
    }

    getRank(node, score, userId, count = 0) {
        if (!node) return count;

        if (score < node.score) {
            return this.getRank(node.left, score, userId, count);
        } else if (score > node.score) {
            return this.getRank(node.right, score, userId, count + this.getSize(node.left) + 1);
        } else {
            // Handle duplicates (same score)
            if (node.userId === userId) {
                return count + this.getSize(node.left) + 1;
            } else {
                return this.getRank(node.right, score, userId, count + this.getSize(node.left) + 1);
            }
        }
    }

    getRankByUserId(userId) {
        const score = this.userMap.get(userId);
        if (score === undefined) return -1;
        return this.getRank(this.root, score, userId);
    }

    getTopUsers(k) {
        const result = [];
        this.inOrderReverse(this.root, result, k);
        return result;
    }

    inOrderReverse(node, result, k) {
        if (!node || result.length >= k) return;
        this.inOrderReverse(node.right, result, k);
        if (result.length < k) {
            result.push({ userId: node.userId, score: node.score });
            this.inOrderReverse(node.left, result, k);
        }
    }
}

// Example usage:
// const leaderboard = new Leaderboard();
// leaderboard.updateScore(1, 100);
// leaderboard.updateScore(2, 200);
// console.log(leaderboard.getRankByUserId(1)); // 2
// console.log(leaderboard.getTopUsers(1)); // [{ userId: 2, score: 200 }]
