#include <iostream>
#include <memory>
#include <vector>
#include <stdexcept>

enum class OrderType { BUY, SELL };

struct Order {
    double price;
    int quantity;
    OrderType type;
    Order(double p, int q, OrderType t) : price(p), quantity(q), type(t) {}
};

class OrderBook {
private:
    struct AVLNode {
        double price;
        std::vector<Order> orders;
        int height;
        std::shared_ptr<AVLNode> left;
        std::shared_ptr<AVLNode> right;
        AVLNode(double p) : price(p), height(1), left(nullptr), right(nullptr) {}
    };

    std::shared_ptr<AVLNode> root;

    int getHeight(std::shared_ptr<AVLNode> node) {
        return node ? node->height : 0;
    }

    int getBalance(std::shared_ptr<AVLNode> node) {
        return node ? getHeight(node->left) - getHeight(node->right) : 0;
    }

    std::shared_ptr<AVLNode> rotateRight(std::shared_ptr<AVLNode> y) {
        auto x = y->left;
        auto T2 = x->right;

        x->right = y;
        y->left = T2;

        y->height = std::max(getHeight(y->left), getHeight(y->right)) + 1;
        x->height = std::max(getHeight(x->left), getHeight(x->right)) + 1;

        return x;
    }

    std::shared_ptr<AVLNode> rotateLeft(std::shared_ptr<AVLNode> x) {
        auto y = x->right;
        auto T2 = y->left;

        y->left = x;
        x->right = T2;

        x->height = std::max(getHeight(x->left), getHeight(x->right)) + 1;
        y->height = std::max(getHeight(y->left), getHeight(y->right)) + 1;

        return y;
    }

    std::shared_ptr<AVLNode> insert(std::shared_ptr<AVLNode> node, double price, const Order& order) {
        if (!node) {
            auto newNode = std::make_shared<AVLNode>(price);
            newNode->orders.push_back(order);
            return newNode;
        }

        if (price < node->price) {
            node->left = insert(node->left, price, order);
        } else if (price > node->price) {
            node->right = insert(node->right, price, order);
        } else {
            node->orders.push_back(order);
            return node;
        }

        node->height = 1 + std::max(getHeight(node->left), getHeight(node->right));

        int balance = getBalance(node);

        if (balance > 1 && price < node->left->price) {
            return rotateRight(node);
        }
        if (balance < -1 && price > node->right->price) {
            return rotateLeft(node);
        }
        if (balance > 1 && price > node->left->price) {
            node->left = rotateLeft(node->left);
            return rotateRight(node);
        }
        if (balance < -1 && price < node->right->price) {
            node->right = rotateRight(node->right);
            return rotateLeft(node);
        }

        return node;
    }

    std::shared_ptr<AVLNode> findPriceLevel(std::shared_ptr<AVLNode> node, double price) {
        if (!node) return nullptr;
        if (price == node->price) return node;
        if (price < node->price) return findPriceLevel(node->left, price);
        return findPriceLevel(node->right, price);
    }

    void validateOrder(const Order& order) {
        if (order.price <= 0 || order.quantity <= 0) {
            throw std::invalid_argument("Invalid order: Price and quantity must be positive.");
        }
    }

public:
    OrderBook() : root(nullptr) {}

    void addOrder(const Order& order) {
        validateOrder(order);
        root = insert(root, order.price, order);
    }

    std::vector<Order> getOrdersAtPrice(double price) {
        auto node = findPriceLevel(root, price);
        return node ? node->orders : std::vector<Order>();
    }
};

int main() {
    OrderBook book;
    book.addOrder(Order(100.5, 10, OrderType::BUY));
    book.addOrder(Order(101.0, 5, OrderType::SELL));
    book.addOrder(Order(100.5, 20, OrderType::BUY));

    auto orders = book.getOrdersAtPrice(100.5);
    for (const auto& order : orders) {
        std::cout << "Price: " << order.price << ", Quantity: " << order.quantity 
                  << ", Type: " << (order.type == OrderType::BUY ? "BUY" : "SELL") << std::endl;
    }
    return 0;
}
