use std::collections::HashMap;
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::path::Path;

#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_word: bool,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            children: HashMap::new(),
            is_word: false,
        }
    }
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::new(),
        }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            node = node.children.entry(c).or_insert_with(TrieNode::new);
        }
        node.is_word = true;
    }

    fn search_prefix(&self, prefix: &str) -> Vec<String> {
        let mut node = &self.root;
        for c in prefix.chars() {
            if let Some(child) = node.children.get(&c) {
                node = child;
            } else {
                return Vec::new();
            }
        }
        self.collect_words(node, prefix)
    }

    fn collect_words(&self, node: &TrieNode, prefix: &str) -> Vec<String> {
        let mut words = Vec::new();
        if node.is_word {
            words.push(prefix.to_string());
        }
        for (c, child) in &node.children {
            let new_prefix = format!("{}{}", prefix, c);
            words.extend(self.collect_words(child, &new_prefix));
        }
        words
    }
}

fn load_dictionary(file_path: &Path) -> std::io::Result<Trie> {
    let file = File::open(file_path)?;
    let reader = BufReader::new(file);
    let mut trie = Trie::new();

    for line in reader.lines() {
        let word = line?;
        if word.is_empty() || !word.is_ascii() {
            continue;
        }
        trie.insert(&word);
    }

    Ok(trie)
}

fn main() {
    let file_path = Path::new("dictionary.txt");
    let trie = match load_dictionary(file_path) {
        Ok(trie) => trie,
        Err(e) => {
            eprintln!("Error loading dictionary: {}", e);
            return;
        }
    };

    let prefix = "app";
    let words = trie.search_prefix(prefix);
    println!("Words with prefix '{}': {:?}", prefix, words);
