use std::sync::{Arc, Mutex};
use std::collections::LinkedList;
use std::thread;

struct Task {
    id: u64,
    description: String,
    priority: u32,
}

struct TaskManager {
    tasks: Arc<Mutex<LinkedList<Task>>>,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            tasks: Arc::new(Mutex::new(LinkedList::new())),
        }
    }

    fn add_task(&self, task: Task) {
        let mut tasks = self.tasks.lock().unwrap();
        tasks.push_back(task);
    }

    fn remove_task(&self, id: u64) -> Option<Task> {
        let mut tasks = self.tasks.lock().unwrap();
        let mut split_list = tasks.split_off(0);
        let mut removed_task = None;

        while let Some(task) = split_list.pop_front() {
            if task.id == id {
                removed_task = Some(task);
                break;
            } else {
                tasks.push_back(task);
            }
        }
        tasks.append(&mut split_list);
        removed_task
    }

    fn get_task_by_priority(&self, priority: u32) -> Vec<Task> {
        let tasks = self.tasks.lock().unwrap();
        tasks.iter()
            .filter(|task| task.priority == priority)
            .map(|task| Task {
                id: task.id,
                description: task.description.clone(),
                priority: task.priority,
            })
            .collect()
    }
}

fn main() {
    let task_manager = Arc::new(TaskManager::new());
    let mut handles = vec![];

    for i in 0..10 {
        let manager_clone = task_manager.clone();
        let handle = thread::spawn(move || {
            let task = Task {
                id: i,
                description: format!("Task {}", i),
                priority: i % 3,
            };
            manager_clone.add_task(task);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let high_priority_tasks = task_manager.get_task_by_priority(2);
    println!("High priority tasks: {}", high_priority_tasks.len());
}
