import sys
from typing import List, Dict, Optional

def fnv1a_hash(email: str) -> int:
    """
    Compute the FNV-1a hash of a string (email).
    """
    if not email:
        return 0

    hash_value = 2166136261  # FNV offset basis
    fnv_prime = 16777619

    for char in email:
        hash_value ^= ord(char)
        hash_value *= fnv_prime

    return hash_value

def is_valid_email(email: str) -> bool:
    """
    Basic email format validation.
    """
    if not email or '@' not in email or '.' not in email:
        return False
    return True

def process_customer_records(customer_records: List[Dict[str, str]], batch_size: int = 1000) -> Dict[str, List[str]]:
    """
    Process customer records in batches, check for duplicate emails using FNV-1a hashing,
    and handle invalid email formats.
    """
    if not customer_records:
        return {"duplicates": [], "invalid_emails": []}

    seen_hashes = set()
    duplicates = []
    invalid_emails = []

    for i in range(0, len(customer_records), batch_size):
        batch = customer_records[i:i + batch_size]

        for record in batch:
            email = record.get("email", "").strip().lower()

            if not is_valid_email(email):
                invalid_emails.append(email)
                continue

            email_hash = fnv1a_hash(email)

            if email_hash in seen_hashes:
                duplicates.append(email)
            else:
                seen_hashes.add(email_hash)

    return {"duplicates": duplicates, "invalid_emails": invalid_emails}

def main():
    # Example usage
    customer_records = [
        {"email": "user1@example.com"},
        {"email": "user2@example.com"},
        {"email": "user1@example.com"},  # Duplicate
        {"email": "invalid_email"},     # Invalid
        {"email": "user3@example.com"},
    ]

    try:
        result = process_customer_records(customer_records)
        print("Duplicates:", result["duplicates"])
        print("Invalid emails:", result["invalid_emails"])
    except Exception as e:
        print(f"Error processing records: {e}", file=sys.stderr)

if __name__ == "__main__":
    main()
