#include <set>
#include <unordered_map>

using namespace std;

class Leaderboard {
private:
    struct Player {
        int id;
        int score;

        bool operator<(const Player& other) const {
            if (score == other.score) {
                return id < other.id; // Tiebreaker: smaller ID first
            }
            return score > other.score; // Higher score first
        }
    };

    set<Player> players;
    unordered_map<int, int> playerScores;

public:
    Leaderboard() {}

    void addScore(int playerId, int score) {
        // If player exists, remove from set first
        if (playerScores.find(playerId) != playerScores.end()) {
            players.erase({playerId, playerScores[playerId]});
            score += playerScores[playerId];
        }
        // Update score and insert into set
        playerScores[playerId] = score;
        players.insert({playerId, score});
    }

    int top(int K) {
        int sum = 0;
        int count = 0;
        for (const auto& player : players) {
            if (count >= K) break;
            sum += player.score;
            count++;
        }
        return sum;
    }

    void reset(int playerId) {
        if (playerScores.find(playerId) != playerScores.end()) {
            players.erase({playerId, playerScores[playerId]});
            playerScores.erase(playerId);
        }
    }

    vector<pair<int, int>> getLeaderboard() {
        vector<pair<int, int>> result;
        for (const auto& player : players) {
            result.emplace_back(player.id, player.score);
        }
        return result;
    }
};

int main() {
    Leaderboard leaderboard;
    // Example usage
    leaderboard.addScore(1, 100);
    leaderboard.addScore(2, 90);
    leaderboard.addScore(3, 90);
    leaderboard.addScore(4, 80);

    // Update a score
    leaderboard.addScore(1, 50); // Player 1 now has 150

    // Get top 2
    cout << "Top 2 scores sum: " << leaderboard.top(2) << endl;

    // Reset a player
    leaderboard.reset(2);

    // Display leaderboard
    auto board = leaderboard.getLeaderboard();
    cout << "Leaderboard:" << endl;
    for (const auto& entry : board) {
        cout << "Player " << entry.first << ": " << entry.second << endl;
    }

    return 0;
}
