import heapq

class PriorityQueue:
    def __init__(self):
        self.heap = []
        self.entry_finder = {}  # To handle duplicates

    def add_task(self, task, priority):
        if task in self.entry_finder:
            self.remove_task(task)
        entry = [priority, task]
        self.entry_finder[task] = entry
        heapq.heappush(self.heap, entry)

    def remove_task(self, task):
        entry = self.entry_finder.pop(task)
        entry[-1] = '<removed-task>'  # Mark as removed

    def pop_task(self):
        while self.heap:
            priority, task = heapq.heappop(self.heap)
            if task != '<removed-task>':
                del self.entry_finder[task]
                return task
        raise KeyError('pop from an empty priority queue')

    def peek_task(self):
        while self.heap:
            priority, task = self.heap[0]
            if task == '<removed-task>':
                heapq.heappop(self.heap)
            else:
                return task
        raise KeyError('peek from an empty priority queue')

    def __len__(self):
        return len(self.entry_finder)

# Example usage:
if __name__ == "__main__":
    pq = PriorityQueue()
    pq.add_task("task1", 3)
    pq.add_task("task2", 1)
    pq.add_task("task3", 2)
    pq.add_task("task3", 0)  # Update priority of task3

    print(pq.peek_task())  # task3
    print(pq.pop_task())   # task3
    print(pq.pop_task())   # task2
    print(pq.pop_task())   # task1
