#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dirent.h>
#include <sys/stat.h>
#include <limits.h>

#define MAX_DOCUMENTS 100
#define MAX_LINE_LENGTH 1024

typedef struct {
    char **lines;
    int line_count;
} Document;

Document documents[MAX_DOCUMENTS];
int document_count = 0;

void handle_error(const char *message) {
    fprintf(stderr, "Error: %s\n", message);
    exit(EXIT_FAILURE);
}

void read_document(const char *filename) {
    if (document_count >= MAX_DOCUMENTS) {
        handle_error("Maximum document limit reached");
    }

    FILE *file = fopen(filename, "r");
    if (!file) {
        handle_error("Failed to open file");
    }

    Document *doc = &documents[document_count];
    doc->line_count = 0;
    doc->lines = malloc(MAX_LINE_LENGTH * sizeof(char *));
    if (!doc->lines) {
        handle_error("Memory allocation failed");
    }

    char line[MAX_LINE_LENGTH];
    while (fgets(line, MAX_LINE_LENGTH, file)) {
        line[strcspn(line, "\n")] = '\0';
        doc->lines[doc->line_count] = strdup(line);
        if (!doc->lines[doc->line_count]) {
            handle_error("Memory allocation failed");
        }
        doc->line_count++;
    }

    fclose(file);
    document_count++;
}

char **find_lcs(int *lcs_length) {
    if (document_count < 1) {
        handle_error("No documents to process");
    }

    int min_lines = documents[0].line_count;
    for (int i = 1; i < document_count; i++) {
        if (documents[i].line_count < min_lines) {
            min_lines = documents[i].line_count;
        }
    }

    char **lcs = malloc(min_lines * sizeof(char *));
    if (!lcs) {
        handle_error("Memory allocation failed");
    }

    *lcs_length = 0;

    for (int i = 0; i < documents[0].line_count; i++) {
        int found_in_all = 1;
        for (int j = 1; j < document_count; j++) {
            int found = 0;
            for (int k = 0; k < documents[j].line_count; k++) {
                if (strcmp(documents[0].lines[i], documents[j].lines[k]) == 0) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                found_in_all = 0;
                break;
            }
        }
        if (found_in_all) {
            lcs[*lcs_length] = strdup(documents[0].lines[i]);
            if (!lcs[*lcs_length]) {
                handle_error("Memory allocation failed");
            }
            (*lcs_length)++;
        }
    }

    return lcs;
}

void free_documents() {
    for (int i = 0; i < document_count; i++) {
        for (int j = 0; j < documents[i].line_count; j++) {
            free(documents[i].lines[j]);
        }
        free(documents[i].lines);
    }
}

void free_lcs(char **lcs, int lcs_length) {
    for (int i = 0; i < lcs_length; i++) {
        free(lcs[i]);
    }
    free(lcs);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        handle_error("Usage: ./program <file1> <file2> ...");
    }

    for (int i = 1; i < argc; i++) {
        read_document(argv[i]);
    }

    int lcs_length;
    char **lcs = find_lcs(&lcs_length);

    printf("Largest Common Subsequence:\n");
    for (int i = 0; i < lcs_length; i++) {
        printf("%s\n", lcs[i]);
    }

    free_documents();
    free_lcs(lcs, lcs_length);

    return 0;
}
