#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define MAX_PACKETS 1000

typedef struct {
    int id;
    int priority; // Higher value = higher priority
    char data[256];
    time_t arrival_time;
} Packet;

typedef struct {
    Packet packets[MAX_PACKETS];
    int size;
} PriorityQueue;

void swap(Packet *a, Packet *b) {
    Packet temp = *a;
    *a = *b;
    *b = temp;
}

void heapify(PriorityQueue *pq, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < pq->size && pq->packets[left].priority > pq->packets[largest].priority)
        largest = left;

    if (right < pq->size && pq->packets[right].priority > pq->packets[largest].priority)
        largest = right;

    if (largest != i) {
        swap(&pq->packets[i], &pq->packets[largest]);
        heapify(pq, largest);
    }
}

void enqueue(PriorityQueue *pq, Packet packet) {
    if (pq->size >= MAX_PACKETS) {
        printf("Queue is full. Cannot enqueue packet.\n");
        return;
    }

    pq->packets[pq->size] = packet;
    int i = pq->size;
    pq->size++;

    while (i > 0 && pq->packets[(i - 1) / 2].priority < pq->packets[i].priority) {
        swap(&pq->packets[i], &pq->packets[(i - 1) / 2]);
        i = (i - 1) / 2;
    }
}

Packet dequeue(PriorityQueue *pq) {
    if (pq->size <= 0) {
        printf("Queue is empty. Returning dummy packet.\n");
        Packet dummy = {-1, -1, "", time(NULL)};
        return dummy;
    }

    Packet root = pq->packets[0];
    pq->packets[0] = pq->packets[pq->size - 1];
    pq->size--;
    heapify(pq, 0);

    return root;
}

void log_packet(Packet p, const char *action) {
    printf("[LOG] Packet ID: %d | Priority: %d | Action: %s | Data: %s | Time: %s",
           p.id, p.priority, action, p.data, ctime(&p.arrival_time));
}

int validate_packet(Packet p) {
    if (p.id < 0 || p.priority < 0 || strlen(p.data) == 0) {
        printf("[ERROR] Invalid packet data.\n");
        return 0;
    }
    return 1;
}

int main() {
    PriorityQueue pq = { .size = 0 };
    srand(time(NULL));

    // Simulate dynamic packet arrival
    for (int i = 0; i < 10; i++) {
        Packet p;
        p.id = i;
        p.priority = rand() % 5; // Priorities 0-4
        snprintf(p.data, sizeof(p.data), "Sample data %d", i);
        p.arrival_time = time(NULL);

        if (!validate_packet(p)) continue;

        enqueue(&pq, p);
        log_packet(p, "Enqueued");
    }

    // Process packets in priority order
    while (pq.size > 0) {
        Packet p = dequeue(&pq);
        log_packet(p, "Dequeued");
        // Process packet here (e.g., forward to network)
    }

    return 0;
}
