use std::fmt;

struct NQueens {
    size: usize,
    solutions: Vec<Vec<usize>>,
}

impl NQueens {
    fn new(size: usize) -> Self {
        NQueens {
            size,
            solutions: Vec::new(),
        }
    }

    fn solve(&mut self) {
        let mut board = vec![0; self.size];
        self.backtrack(&mut board, 0);
    }

    fn backtrack(&mut self, board: &mut Vec<usize>, row: usize) {
        if row == self.size {
            self.solutions.push(board.clone());
            return;
        }

        for col in 0..self.size {
            if self.is_safe(board, row, col) {
                board[row] = col;
                self.backtrack(board, row + 1);
            }
        }
    }

    fn is_safe(&self, board: &[usize], row: usize, col: usize) -> bool {
        for i in 0..row {
            if board[i] == col || 
               board[i].abs_diff(col) == row - i {
                return false;
            }
        }
        true
    }

    fn print_solutions(&self) {
        for sol in &self.solutions {
            self.print_board(sol);
            println!();
        }
    }

    fn print_board(&self, board: &[usize]) {
        for row in 0..self.size {
            for col in 0..self.size {
                if board[row] == col {
                    print!("Q ");
                } else {
                    print!(". ");
                }
            }
            println!();
        }
    }
}

impl fmt::Display for NQueens {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        writeln!(f, "Found {} solutions for {}-Queens problem:", self.solutions.len(), self.size)?;
        for sol in &self.solutions {
            for row in 0..self.size {
                for col in 0..self.size {
                    if sol[row] == col {
                        write!(f, "Q ")?;
                    } else {
                        write!(f, ". ")?;
                    }
                }
                writeln!(f)?;
            }
            writeln!(f)?;
        }
        Ok(())
    }
}

fn main() {
    let size = 8; // Change this for custom board size
    let mut n_queens = NQueens::new(size);
    n_queens.solve();
    println!("{}", n_queens);
}
