function findShortestPath(graph, start, end) {
    if (!graph || typeof graph !== 'object' || Array.isArray(graph)) {
        throw new Error('Invalid graph input: must be an object');
    }
    if (!graph[start] || !graph[end]) {
        throw new Error('Start or end intersection not found in graph');
    }

    const distances = {};
    const previous = {};
    const nodes = new Set();
    const queue = new PriorityQueue();

    for (const intersection in graph) {
        if (graph.hasOwnProperty(intersection)) {
            distances[intersection] = intersection === start ? 0 : Infinity;
            queue.enqueue(intersection, distances[intersection]);
            nodes.add(intersection);
        }
    }

    while (!queue.isEmpty()) {
        const current = queue.dequeue().element;
        nodes.delete(current);

        if (current === end) {
            const path = [];
            let temp = current;
            while (temp) {
                path.unshift(temp);
                temp = previous[temp];
            }
            return path;
        }

        if (!graph[current] || distances[current] === Infinity) continue;

        for (const neighbor in graph[current]) {
            if (graph[current].hasOwnProperty(neighbor)) {
                const alt = distances[current] + graph[current][neighbor];
                if (alt < distances[neighbor]) {
                    distances[neighbor] = alt;
                    previous[neighbor] = current;
                    queue.enqueue(neighbor, distances[neighbor]);
                }
            }
        }
    }

    throw new Error('No path found from start to end intersection');
}

class PriorityQueue {
    constructor() {
        this.elements = [];
    }

    enqueue(element, priority) {
        this.elements.push({ element, priority });
        this.elements.sort((a, b) => a.priority - b.priority);
    }

    dequeue() {
        return this.elements.shift();
    }

    isEmpty() {
        return this.elements.length === 0;
    }
}
