import java.io.*;
import java.util.*;
import java.nio.file.*;
import java.nio.charset.*;

public class ConfigManager {
    private Map<String, String> configMap;
    private String[] keys;
    private int[] hashTable;
    private int size;

    public ConfigManager(String filePath) throws IOException {
        loadConfig(filePath);
    }

    private void loadConfig(String filePath) throws IOException {
        List<String> lines = Files.readAllLines(Paths.get(filePath), StandardCharsets.UTF_8);
        configMap = new HashMap<>();
        Set<String> duplicateKeys = new HashSet<>();

        for (String line : lines) {
            line = line.trim();
            if (line.isEmpty() || line.startsWith("#")) continue;

            String[] parts = line.split("=", 2);
            if (parts.length != 2) {
                throw new IOException("Invalid key-value format: " + line);
            }

            String key = parts[0].trim();
            String value = parts[1].trim();

            if (configMap.containsKey(key)) {
                duplicateKeys.add(key);
            }
            configMap.put(key, value);
        }

        // Resolve duplicates (last occurrence wins)
        for (String key : duplicateKeys) {
            System.err.println("Warning: Duplicate key found: " + key);
        }

        buildPerfectHash();
    }

    private void buildPerfectHash() {
        size = configMap.size();
        keys = new String[size];
        hashTable = new int[size];
        Arrays.fill(hashTable, -1);

        int index = 0;
        for (String key : configMap.keySet()) {
            keys[index++] = key;
        }

        // Simple perfect hash implementation (for demonstration)
        // In production, use a proper minimal perfect hash library like MPH
        for (int i = 0; i < size; i++) {
            int hash = Math.abs(keys[i].hashCode()) % size;
            while (hashTable[hash] != -1) {
                hash = (hash + 1) % size;
            }
            hashTable[hash] = i;
        }
    }

    public String get(String key) {
        int hash = Math.abs(key.hashCode()) % size;
        int attempts = 0;

        while (attempts < size) {
            int index = hashTable[hash];
            if (index != -1 && keys[index].equals(key)) {
                return configMap.get(key);
            }
            hash = (hash + 1) % size;
            attempts++;
        }
        return null;
    }

    public void reload(String filePath) throws IOException {
        loadConfig(filePath);
    }

    public static void main(String[] args) {
        try {
            ConfigManager manager = new ConfigManager("config.properties");
            System.out.println(manager.get("db.host"));
