#include <iostream>
#include <vector>
#include <fstream>
#include <nlohmann/json.hpp>

using json = nlohmann::json;
using namespace std;

const int N = 8;
vector<vector<int>> solutions;

bool isSafe(const vector<vector<int>>& board, int row, int col) {
    for (int i = 0; i < col; ++i)
        if (board[row][i])
            return false;
    for (int i = row, j = col; i >= 0 && j >= 0; --i, --j)
        if (board[i][j])
            return false;
    for (int i = row, j = col; j >= 0 && i < N; ++i, --j)
        if (board[i][j])
            return false;
    return true;
}

bool solveNQUtil(vector<vector<int>>& board, int col) {
    if (col >= N) {
        solutions.push_back(board);
        return true;
    }
    bool res = false;
    for (int i = 0; i < N; ++i) {
        if (isSafe(board, i, col)) {
            board[i][col] = 1;
            res = solveNQUtil(board, col + 1) || res;
            board[i][col] = 0;
        }
    }
    return res;
}

void loadInitialPositions(vector<vector<int>>& board, const string& filename) {
    ifstream file(filename);
    if (!file.is_open()) {
        cerr << "Error opening file: " << filename << endl;
        return;
    }
    json j;
    file >> j;
    for (auto& pos : j["queens"]) {
        int row = pos["row"];
        int col = pos["col"];
        if (row < 0 || row >= N || col < 0 || col >= N) {
            cerr << "Invalid position: (" << row << "," << col << ")" << endl;
            continue;
        }
        if (board[row][col] == 1) {
            cerr << "Duplicate queen at: (" << row << "," << col << ")" << endl;
            continue;
        }
        board[row][col] = 1;
    }
}

void printBoard(const vector<vector<int>>& board) {
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j)
            cout << (board[i][j] ? "Q " : ". ");
        cout << endl;
    }
    cout << endl;
}

int main() {
    vector<vector<int>> board(N, vector<int>(N, 0));
    loadInitialPositions(board, "input.json");

    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            if (board[i][j] == 1 && !isSafe(board, i, j)) {
                cerr << "Invalid initial configuration: Queens attack each other." << endl;
                return 1;
            }
        }
    }

    solveNQUtil(board, 0);

    if (solutions.empty()) {
        cout << "No valid configurations found." << endl;
    } else {
        for (const auto& sol : solutions) {
            printBoard(sol);
        }
        cout << "Total solutions: " << solutions.size() << endl;
    }
    return 0;
}
