#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <climits>

struct Point {
    double x, y;
    int index;
};

double distance(const Point& a, const Point& b) {
    return std::sqrt((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y));
}

bool compareX(const Point& a, const Point& b) {
    return a.x < b.x;
}

bool compareY(const Point& a, const Point& b) {
    return a.y < b.y;
}

void findClosestPair(const std::vector<Point>& points, int left, int right, Point& user, Point& nearest, double& minDist) {
    if (left >= right) return;

    int mid = (left + right) / 2;
    findClosestPair(points, left, mid, user, nearest, minDist);
    findClosestPair(points, mid + 1, right, user, nearest, minDist);

    for (int i = left; i <= right; ++i) {
        double dist = distance(points[i], user);
        if (dist < minDist) {
            minDist = dist;
            nearest = points[i];
        }
    }
}

Point findNearestCoffeeShop(std::vector<Point>& coffeeShops, Point user) {
    std::sort(coffeeShops.begin(), coffeeShops.end(), compareX);
    Point nearest;
    double minDist = std::numeric_limits<double>::max();
    findClosestPair(coffeeShops, 0, coffeeShops.size() - 1, user, nearest, minDist);
    return nearest;
}

int main() {
    std::vector<Point> coffeeShops = {{1.0, 2.0, 0}, {3.0, 4.0, 1}, {5.0, 6.0, 2}};
    Point user = {2.0, 3.0, -1};
    Point nearest = findNearestCoffeeShop(coffeeShops, user);
    std::cout << "Nearest coffee shop is at (" << nearest.x << ", " << nearest.y << ")\n";
    return 0;
}
