#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int tsp(const vector<vector<int>>& distance) {
    int n = distance.size();
    if (n == 0) return 0;

    vector<vector<int>> dp(1 << n, vector<int>(n, INT_MAX));
    dp[1][0] = 0; // Starting at city 0 (mask 000..1)

    for (int mask = 1; mask < (1 << n); ++mask) {
        for (int last = 0; last < n; ++last) {
            if (!(mask & (1 << last))) continue;
            if (dp[mask][last] == INT_MAX) continue;

            for (int next = 0; next < n; ++next) {
                if (mask & (1 << next)) continue;
                int new_mask = mask | (1 << next);
                if (dp[new_mask][next] > dp[mask][last] + distance[last][next]) {
                    dp[new_mask][next] = dp[mask][last] + distance[last][next];
                }
            }
        }
    }

    int final_mask = (1 << n) - 1;
    int min_cost = INT_MAX;
    for (int last = 1; last < n; ++last) {
        if (dp[final_mask][last] != INT_MAX && distance[last][0] != INT_MAX) {
            min_cost = min(min_cost, dp[final_mask][last] + distance[last][0]);
        }
    }

    return min_cost;
}

int main() {
    // Example usage:
    vector<vector<int>> distance = {
        {0, 10, 15, 20},
        {10, 0, 35, 25},
        {15, 35, 0, 30},
        {20, 25, 30, 0}
    };

    int min_distance = tsp(distance);
    cout << "Minimum distance for the trip: " << min_distance << endl;

    return 0;
}
